import java.util.HashSet;
import java.util.Set;
import java.lang.Math;

public static long solve(long[] nums) {
    // 1. Create a set S of unique elements for O(1) lookup.
    Set<Long> S = new HashSet<>();
    for (long num : nums) {
        S.add(num);
    }

    long totalSum = 0;

    // 2. For each element x in nums, find the minimum divisor d present in S.
    for (long x : nums) {
        // x itself is always a divisor present in S (since x is in nums).
        long min_divisor = x;

        // Iterate up to sqrt(x) to find all divisors.
        // Since x <= 10^5, sqrt(x) is small.
        long limit = (long) Math.sqrt(x);

        for (long d = 1; d <= limit; d++) {
            if (x % d == 0) {
                // d is a divisor

                // Check d
                if (S.contains(d)) {
                    if (d < min_divisor) {
                        min_divisor = d;
                    }
                }

                // Check x/d (the complementary divisor)
                long d_prime = x / d;
                if (S.contains(d_prime)) {
                    if (d_prime < min_divisor) {
                        min_divisor = d_prime;
                    }
                }
            }
        }

        totalSum += min_divisor;
    }

    return totalSum;
}

