import java.util.ArrayList;
import java.util.List;

public class Solution {
    public static long solve(long[] nums) {
        final int MAX_VAL = 100000;

        // Step 1 & 2: Count occurrences and identify unique elements S
        // Since values are up to 10^5, we use arrays for efficiency
        int[] counts = new int[MAX_VAL + 1];
        boolean[] isPresent = new boolean[MAX_VAL + 1];
        List<Integer> uniqueElements = new ArrayList<>();

        for (long numL : nums) {
            int num = (int) numL;
            if (num <= MAX_VAL) {
                counts[num]++;
                if (!isPresent[num]) {
                    isPresent[num] = true;
                    uniqueElements.add(num);
                }
            }
        }

        long totalMinSum = 0;

        // Step 3 & 4: For each unique element s, find M(s) and calculate contribution to the sum
        for (int s : uniqueElements) {
            int minDivisorInS = s;

            // Find the minimum divisor d of s such that d is present in nums (d in S)
            // We check divisors up to sqrt(s)
            for (int d = 1; d * d <= s; d++) {
                if (s % d == 0) {
                    // Check divisor d
                    if (isPresent[d]) {
                        minDivisorInS = Math.min(minDivisorInS, d);
                    }

                    // Check conjugate divisor s/d
                    int dPrime = s / d;
                    if (dPrime != d && isPresent[dPrime]) {
                        minDivisorInS = Math.min(minDivisorInS, dPrime);
                    }
                }
            }

            // Add the contribution: count[s] * M(s)
            totalMinSum += (long)counts[s] * minDivisorInS;
        }

        return totalMinSum;
    }
}

