public static long solve(long[] nums) {
    // Constraints: 1 <= nums[i] <= 10^5.
    final int MAX_VAL = 100000;

    // 1. Determine the set V of unique values present in nums.
    // Use a boolean array for O(1) lookup since max value is small.
    boolean[] inV = new boolean[MAX_VAL + 1];
    for (long x : nums) {
        int val = (int) x;
        inV[val] = true;
    }

    long totalSum = 0;

    // 2. For each element X, find the smallest divisor Y* present in V.
    for (long X_long : nums) {
        int X = (int) X_long;

        // Initialize the smallest reachable value to X itself, 
        // as X is always a divisor of X and X is in V.
        int Y_star = X;

        // Search for divisors up to sqrt(X)
        int limit = (int) Math.sqrt(X);
        for (int d = 1; d <= limit; d++) {
            if (X % d == 0) {
                // Check divisor d
                if (d < Y_star && inV[d]) {
                    Y_star = d;
                }

                // Check conjugate divisor d' = X / d
                int d_prime = X / d;
                if (d_prime < Y_star && inV[d_prime]) {
                    Y_star = d_prime;
                }
            }
        }

        // Y_star is now the smallest value in V that divides X.
        totalSum += Y_star;
    }

    return totalSum;
}

